name: Deploy to master

on:
  push:
    branches:
      - master
  workflow_dispatch:

jobs:
  deploy:
    runs-on: [self-hosted, self-hosted-kamakshimoney]

    steps:
      - name: Checkout code
        uses: actions/checkout@v4

      - name: Deploy latest code
        run: |
          echo ">>> Switching to project directory"
          cd /home/ubuntu/api_code/Kamakshimoney-onboarding

          echo ">>> Load NVM and use Node 20"
          export NVM_DIR="/home/ubuntu/.nvm"
          [ -s "$NVM_DIR/nvm.sh" ] && . "$NVM_DIR/nvm.sh"

          nvm use 20.20.0

          echo ">>> Node version"
          node -v
          npm -v
          which node

          echo ">>> Fetching latest code from master branch"
          git fetch origin
          git reset --hard origin/master

          echo ">>> Install dependency"
          npm install --legacy-peer-deps

          echo ">>> Build project"
          CI=false npm run build

          echo ">>> Remove old files from S3"
          aws s3 rm s3://loan.kamakshimoney.com --recursive

          echo ">>> Upload new build to S3"
          aws s3 cp dist/ s3://loan.kamakshimoney.com/ --recursive

          echo ">>> CloudFront cache invalidation"
          aws cloudfront create-invalidation \
            --distribution-id EHN3KH6MXJSMZ \
            --paths "/*"

          echo ">>> Showing last 10 commits"
          git log -10 --oneline

          echo ">>> Deployment completed successfully!"



name: Deploy to kamakshimoney-onboarding-preprod

on:
  push:
    branches:
      - preprod
  workflow_dispatch:

jobs:
  deploy:
    runs-on: [self-hosted, self-hosted-kamakshimoney]

    steps:
      - name: Checkout code
        uses: actions/checkout@v4


      - name: Run remote script
        run: |
          ssh -o StrictHostKeyChecking=no ubuntu@13.232.129.191 << 'EOF'
            #!/bin/bash
            set -e  # Exit immediately if a command exits with a non-zero status
            set -x  # Print commands and their arguments as they are executed

            echo "Starting deployment to pre-prod environment"

            echo "Navigating to Kamakshimoney-onboarding directory"
            cd /var/www/preprod/Kamakshimoney-onboarding
            echo "Pulling latest changes from preprod branch"
            git reset --hard origin/preprod
            git pull origin preprod
            echo "Installing npm dependencies"
            npm install
            npm run build

            echo "Deployment to kamakshi-pre-prod completed successfully"
          EOF



